    public static class ReviewFormatting
    {
        public static IHtmlContent RenderBasicFormatting(string? input)
        {
            input ??= "";

            // Encode first to prevent XSS, then apply limited formatting replacements.
            var encoded = HtmlEncoder.Default.Encode(input);

            // Normalize newlines then convert to <br/>
            encoded = encoded.Replace("\r\n", "\n").Replace("\r", "\n");
            var lines = encoded.Split('\n');

            var sb = new StringBuilder(encoded.Length + 32);

            for (int i = 0; i < lines.Length; i++)
            {
                if (i > 0) sb.Append("<br/>");
                sb.Append(ApplyBoldItalic(lines[i]));
            }

            return new HtmlString(sb.ToString());
        }

        private static string ApplyBoldItalic(string encodedLine)
        {
            // Apply **bold** and *italic* on already-encoded text.
            // This is intentionally minimal; it does not support nesting or escaping.
            var s = encodedLine;
            s = ReplaceDelimited(s, "**", "<strong>", "</strong>");
            s = ReplaceDelimited(s, "*", "<em>", "</em>");
            return s;
        }

        private static string ReplaceDelimited(string input, string delimiter, string openTag, string closeTag)
        {
            int start = 0;
            while (true)
            {
                int a = input.IndexOf(delimiter, start, StringComparison.Ordinal);
                if (a < 0) break;

                int b = input.IndexOf(delimiter, a + delimiter.Length, StringComparison.Ordinal);
                if (b < 0) break;

                // Avoid empty spans
                if (b == a + delimiter.Length)
                {
                    start = b + delimiter.Length;
                    continue;
                }

                input = input.Substring(0, a)
                        + openTag
                        + input.Substring(a + delimiter.Length, b - (a + delimiter.Length))
                        + closeTag
                        + input.Substring(b + delimiter.Length);

                start = a + openTag.Length + closeTag.Length;
            }

            return input;
        }
    }

    public class ProductController : Controller
    {
        private readonly AppDbContext _db;

        public ProductController(AppDbContext db)
        {
            _db = db;
        }

        [HttpGet("/product/{id:int}")]
        public async Task<IActionResult> Details(int id)
        {
            var product = await _db.Products.AsNoTracking()
                .Where(p => p.Id == id)
                .Select(p => new
                {
                    p.Id,
                    p.Name
                })
                .SingleOrDefaultAsync();

            if (product == null) return NotFound();

            var reviews = await _db.Reviews.AsNoTracking()
                .Where(r => r.ProductId == id)
                .OrderByDescending(r => r.CreatedUtc)
                .Select(r => new
                {
                    r.AuthorName,
                    r.Body,
                    r.CreatedUtc
                })
                .ToListAsync();

            var vm = new ProductPageViewModel
            {
                ProductId = product.Id,
                ProductName = product.Name,
                Reviews = reviews.Select(r => new ReviewViewModel
                {
                    AuthorName = r.AuthorName,
                    CreatedUtc = r.CreatedUtc,
                    BodyHtml = ReviewFormatting.RenderBasicFormatting(r.Body)
                }).ToList()
            };

            return View("Details", vm);
        }
    }
