/* Views/Product/Details.cshtml */
@model MyStore.Web.ProductPageViewModel
@{
    ViewData["Title"] = Model.ProductName;
}
<h1>@Model.ProductName</h1>

<section aria-label="Reviews">
    <h2>Reviews</h2>

    @if (Model.Reviews.Count == 0)
    {
        <p>No reviews yet.</p>
    }
    else
    {
        <ul>
            @foreach (var r in Model.Reviews)
            {
                <li style="margin-bottom:1rem;">
                    <div>
                        <strong>@r.AuthorName</strong>
                        <span style="color:#666;">(@r.CreatedUtc.ToLocalTime().ToString("g"))</span>
                    </div>
                    <div>@r.BodyHtml</div>
                </li>
            }
        </ul>
    }

    <p><small>Formatting supported: *italic* and **bold**.</small></p>
</section>